<template>
	<view class="container">
		<view class="header">
			<text class="title">生产计划管理</text>
			<button class="add-btn" @click="addPlan">+ 新增计划</button>
		</view>
		
		<view class="filter-section">
			<view class="filter-item">
				<text class="filter-label">状态：</text>
				<view class="filter-options">
					<text class="filter-option" :class="{ active: selectedStatus === 'all' }" @click="selectedStatus = 'all'">全部</text>
					<text class="filter-option" :class="{ active: selectedStatus === 'pending' }" @click="selectedStatus = 'pending'">待生产</text>
					<text class="filter-option" :class="{ active: selectedStatus === 'processing' }" @click="selectedStatus = 'processing'">生产中</text>
					<text class="filter-option" :class="{ active: selectedStatus === 'completed' }" @click="selectedStatus = 'completed'">已完成</text>
				</view>
			</view>
		</view>
		
		<view class="plan-list">
			<view class="plan-item" v-for="(plan, index) in filteredPlans" :key="index">
				<view class="plan-header">
					<text class="plan-id">计划#{{ plan.id }}</text>
					<text class="plan-status" :class="plan.status">{{ plan.statusText }}</text>
				</view>
				
				<view class="plan-content">
					<view class="content-row">
						<text class="label">产品名称：</text>
						<text class="value">{{ plan.product }}</text>
					</view>
					<view class="content-row">
						<text class="label">计划数量：</text>
						<text class="value">{{ plan.quantity }} 件</text>
					</view>
					<view class="content-row">
						<text class="label">开始时间：</text>
						<text class="value">{{ plan.startDate }}</text>
					</view>
					<view class="content-row">
						<text class="label">结束时间：</text>
						<text class="value">{{ plan.endDate }}</text>
					</view>
					<view class="content-row">
						<text class="label">生产进度：</text>
						<view class="progress-container">
							<view class="progress-bar" :style="{ width: plan.progress + '%' }"></view>
						</view>
						<text class="progress-text">{{ plan.progress }}%</text>
					</view>
				</view>
				
				<view class="plan-actions">
					<button class="action-btn view" @click="viewPlan(plan.id)">查看详情</button>
					<button class="action-btn edit" @click="editPlan(plan.id)">编辑</button>
					<button class="action-btn start" v-if="plan.status === 'pending'" @click="startProduction(plan.id)">开始生产</button>
					<button class="action-btn complete" v-if="plan.status === 'processing'" @click="completeProduction(plan.id)">完成生产</button>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
export default {
	data() {
		return {
			selectedStatus: 'all',
			plans: [
				{ id: 'P001', product: '产品A', quantity: 500, startDate: '2026-01-11', endDate: '2026-01-15', status: 'processing', statusText: '生产中', progress: 60 },
				{ id: 'P002', product: '产品B', quantity: 300, startDate: '2026-01-12', endDate: '2026-01-16', status: 'pending', statusText: '待生产', progress: 0 },
				{ id: 'P003', product: '产品C', quantity: 800, startDate: '2026-01-10', endDate: '2026-01-14', status: 'completed', statusText: '已完成', progress: 100 },
				{ id: 'P004', product: '产品D', quantity: 200, startDate: '2026-01-11', endDate: '2026-01-13', status: 'processing', statusText: '生产中', progress: 85 },
				{ id: 'P005', product: '产品E', quantity: 600, startDate: '2026-01-13', endDate: '2026-01-17', status: 'pending', statusText: '待生产', progress: 0 }
			]
		};
	},
	computed: {
		filteredPlans() {
			if (this.selectedStatus === 'all') {
				return this.plans;
			}
			return this.plans.filter(plan => plan.status === this.selectedStatus);
		}
	},
	methods: {
		addPlan() {
			uni.showToast({
				title: '新增计划功能开发中',
				icon: 'none'
			});
		},
		viewPlan(id) {
			uni.showToast({
				title: `查看计划#${id}`,
				icon: 'none'
			});
		},
		editPlan(id) {
			uni.showToast({
				title: `编辑计划#${id}`,
				icon: 'none'
			});
		},
		startProduction(id) {
			const plan = this.plans.find(p => p.id === id);
			if (plan) {
				plan.status = 'processing';
				plan.statusText = '生产中';
				uni.showToast({
					title: '已开始生产',
					icon: 'success'
				});
			}
		},
		completeProduction(id) {
			const plan = this.plans.find(p => p.id === id);
			if (plan) {
				plan.status = 'completed';
				plan.statusText = '已完成';
				plan.progress = 100;
				uni.showToast({
					title: '已完成生产',
					icon: 'success'
				});
			}
		}
	}
};
</script>

<style scoped>
.container {
	padding: 20rpx;
	background-color: #f5f5f5;
	min-height: 100vh;
}

.header {
	display: flex;
	justify-content: space-between;
	align-items: center;
	padding: 20rpx;
	background-color: #fff;
	border-radius: 10rpx;
	margin-bottom: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.title {
	font-size: 36rpx;
	font-weight: bold;
	color: #333;
}

.add-btn {
	padding: 12rpx 24rpx;
	background-color: #007aff;
	color: #fff;
	border: none;
	border-radius: 20rpx;
	font-size: 24rpx;
	cursor: pointer;
}

.filter-section {
	padding: 20rpx;
	background-color: #fff;
	border-radius: 10rpx;
	margin-bottom: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.filter-item {
	display: flex;
	align-items: center;
}

.filter-label {
	font-size: 28rpx;
	color: #666;
	margin-right: 20rpx;
}

.filter-options {
	display: flex;
	gap: 15rpx;
}

.filter-option {
	padding: 8rpx 16rpx;
	font-size: 24rpx;
	color: #8e8e93;
	background-color: #f0f0f0;
	border-radius: 20rpx;
	cursor: pointer;
	transition: all 0.3s;
}

.filter-option.active {
	background-color: #007aff;
	color: #fff;
}

.plan-list {
	display: flex;
	flex-direction: column;
	gap: 20rpx;
}

.plan-item {
	background-color: #fff;
	border-radius: 10rpx;
	padding: 20rpx;
	box-shadow: 0 2rpx 10rpx rgba(0, 0, 0, 0.1);
}

.plan-header {
	display: flex;
	justify-content: space-between;
	align-items: center;
	margin-bottom: 15rpx;
	padding-bottom: 15rpx;
	border-bottom: 1rpx solid #f0f0f0;
}

.plan-id {
	font-size: 30rpx;
	font-weight: bold;
	color: #333;
}

.plan-status {
	font-size: 24rpx;
	padding: 4rpx 12rpx;
	border-radius: 15rpx;
	font-weight: bold;
}

.plan-status.processing {
	background-color: #e8f0fe;
	color: #007aff;
}

.plan-status.pending {
	background-color: #f0f0f0;
	color: #8e8e93;
}

.plan-status.completed {
	background-color: #e8f8f5;
	color: #4cd964;
}

.plan-content {
	margin-bottom: 15rpx;
}

.content-row {
	display: flex;
	margin-bottom: 12rpx;
	align-items: center;
}

.label {
	font-size: 26rpx;
	color: #666;
	width: 150rpx;
}

.value {
	font-size: 26rpx;
	color: #333;
	flex: 1;
}

.progress-container {
	flex: 1;
	height: 10rpx;
	background-color: #f0f0f0;
	border-radius: 5rpx;
	margin: 0 15rpx;
	overflow: hidden;
}

.progress-bar {
	height: 100%;
	background-color: #007aff;
	transition: width 0.3s ease;
}

.progress-text {
	font-size: 24rpx;
	color: #007aff;
	font-weight: bold;
}

.plan-actions {
	display: flex;
	justify-content: flex-end;
	gap: 10rpx;
	padding-top: 15rpx;
	border-top: 1rpx solid #f0f0f0;
}

.action-btn {
	padding: 10rpx 20rpx;
	border: 1rpx solid #007aff;
	border-radius: 20rpx;
	font-size: 22rpx;
	cursor: pointer;
	transition: all 0.3s;
}

.action-btn.view {
	background-color: #fff;
	color: #007aff;
}

.action-btn.edit {
	background-color: #fff;
	color: #ff9500;
	border-color: #ff9500;
}

.action-btn.start {
	background-color: #4cd964;
	color: #fff;
	border-color: #4cd964;
}

.action-btn.complete {
	background-color: #ff2d55;
	color: #fff;
	border-color: #ff2d55;
}

.action-btn:hover {
	opacity: 0.8;
}
</style>